#include <iostream>#include <vector>#include <algorithm>#include <set> using namespace std; void solve() {    int n;    cin >> n;    vector<int> a(n);    set<int> unique_elements;    bool has_duplicates = false;     for (int i = 0; i < n; i++) {        cin >> a[i];        if (unique_elements.count(a[i])) {            has_duplicates = true;        }        unique_elements.insert(a[i]);    }     if (has_duplicates) {        cout << -1 << endl;    } else {        sort(a.begin(), a.end(), greater<int>());                for (int i = 0; i < n; i++) {            cout << a[i]<<" ";        }        cout << endl;    }} int main() {    int t;    if (!(cin >> t)) return 0;    while (t--) {        solve();    }    return 0;}